#include<bits/stdc++.h>
using namespace std;
long long a, b, c,n;
int main() {
	cin >> n;
    a=2;
    b=n-1;
    c=6662333;
	long long x = b;
		long long lest = a%c;
		long long ans = 1;
    if(b==0){
        printf("%lld^%lld mod %lld=1", a, b, c);
        return 0;
    }
	while (x) {
		int m = x % 2;
		if (m) {
			ans =ans*lest % c;
		}
		x /= 2;
		lest = (lest%c * lest%c) % c;
	}
    ans%=c;
	printf("%lld",ans);
	return 0;
}
